// =====================================================================
// CONFIG -- edit everything here. This node + "Prepare Sources" are
// the ONLY two nodes you need to touch to use this workflow.
// =====================================================================
const CONFIG = {
  // Where finished articles are POSTed (your backend / CMS endpoint).
  // See docs/configuration.md for the exact JSON payload your API receives.
  apiUrl: 'https://YOUR-SITE.example.com/api/v1/articles',

  // Simple header-based auth for the endpoint above.
  // TIP: for production, prefer an n8n "Header Auth" credential on the
  // "POST Article" node instead of keeping the secret in the workflow JSON.
  authHeaderName: 'X-Api-Key',
  authHeaderValue: 'YOUR_API_SECRET',

  // How many of the newest items to take from each feed per run.
  maxItemsPerFeed: 5,

  // Limits applied to generated text fields.
  shortDescriptionWords: 30,      // words kept in the short description
  shortDescriptionMaxChars: 500,  // hard cap on short descriptions before POSTing
  maxDescriptionChars: 5000,      // cap on full article text (also keeps LLM cost down)

  // Used when neither the RSS item nor the article page provides an image.
  placeholderImage: 'https://placehold.co/600x400?text=News'
};

return [{ json: CONFIG }];

// =====================================================================
// SOURCES & CATEGORIES -- the only other node you need to edit.
// =====================================================================

// CATEGORIES maps a human-friendly slug (used in SOURCES below) to the
// numeric category ID expected by YOUR backend. Add as many as you like.
const CATEGORIES = {
  'technology': 1,
  'business':   2,
  'news':       3
};

// SOURCES -- one entry per RSS/Atom feed. Fields:
//   name         friendly label (used in logs and skip reports)
//   feedUrl      the RSS/Atom feed URL
//   lang         'en' or 'ar' -- the language the feed publishes in.
//                The workflow auto-fills the OTHER language via the
//                "Translate" node, so every article ends up bilingual.
//   categorySlug must be a key of CATEGORIES above.
//
// The entries below are public, well-known feeds kept as EXAMPLES --
// replace them with your own.
const SOURCES = [
  { name: 'BBC Technology',          feedUrl: 'https://feeds.bbci.co.uk/news/technology/rss.xml', lang: 'en', categorySlug: 'technology' },
  { name: 'Engadget',                feedUrl: 'https://www.engadget.com/rss.xml',                 lang: 'en', categorySlug: 'technology' },
  { name: 'Guardian Business',       feedUrl: 'https://www.theguardian.com/uk/business/rss',      lang: 'en', categorySlug: 'business' },
  { name: 'BBC Arabic',              feedUrl: 'https://feeds.bbci.co.uk/arabic/rss.xml',          lang: 'ar', categorySlug: 'news' },
  { name: 'Sky News Arabia Business', feedUrl: 'https://www.skynewsarabia.com/rss/business.xml',  lang: 'ar', categorySlug: 'business' }
];

// --------------- no edits needed below this line ---------------------
// Emits one item per source, with the numeric category_id resolved.
return SOURCES.map(s => {
  const category_id = CATEGORIES[s.categorySlug];
  if (category_id === undefined) {
    throw new Error('Source "' + s.name + '" uses unknown categorySlug "' + s.categorySlug + '". Add it to CATEGORIES first.');
  }
  return { json: { name: s.name, feedUrl: s.feedUrl, lang: s.lang, categorySlug: s.categorySlug, category_id } };
});

// =====================================================================
// BUILD ARTICLES -- normalize raw RSS items into article objects.
// - Takes the newest N items per feed (CONFIG.maxItemsPerFeed)
// - Skips items with no usable URL
// - Skips items already published in a previous run (dedupe via
//   workflow static data -- survives between executions)
// - Fills the fields of the SOURCE language; the other language is
//   left empty for the "Translate" node to fill.
// =====================================================================
const crypto = require('crypto');
const cfg = $('Config').first().json;
const source = $('Per Source').item.json;

// Persistent dedupe store: { articleId: timestamp }.
// NOTE: static data only persists for ACTIVE (scheduled/webhook) runs;
// manual test runs always start fresh. See docs/architecture.md.
const sd = $getWorkflowStaticData('global');
sd.seenIds = sd.seenIds || {};

const stripHtml = s => (s || '').replace(/<[^>]*>/g, ' ').replace(/&nbsp;/g, ' ').replace(/\s+/g, ' ').trim();
const firstWords = (s, n) => { const w = (s || '').split(/\s+/).filter(Boolean); return w.length <= n ? w.join(' ') : w.slice(0, n).join(' ') + '...'; };
// Stable 16-char ID derived from the article URL -- used for dedupe.
const articleId = url => crypto.createHash('sha256').update(url).digest('hex').slice(0, 16);

// Best image the FEED itself offers (enclosure / media:content / media:thumbnail).
// If none, "Resolve Image" later falls back to the page's og:image.
const pickImage = j => {
  if (j.enclosure && j.enclosure.url) return j.enclosure.url;
  const mc = j['media:content']; if (mc && mc['$'] && mc['$'].url) return mc['$'].url;
  const mt = j['media:thumbnail']; if (mt && mt['$'] && mt['$'].url) return mt['$'].url;
  return '';
};

const items = $input.all().slice(0, cfg.maxItemsPerFeed);
const out = [];
let skippedNoUrl = 0, skippedSeen = 0;

for (const it of items) {
  const j = it.json || {};
  const url = (j.link || j.guid || j.id || '').toString().trim();
  if (!url) { skippedNoUrl++; continue; }
  const id = articleId(url);
  if (sd.seenIds[id]) { skippedSeen++; continue; }

  const title = stripHtml(j.title) || '(untitled)';
  const body = stripHtml(j.contentSnippet || j.content || j.summary || j.description || '');
  const description = body || title;
  const short_description = firstWords(body, cfg.shortDescriptionWords) || title;
  const isAr = source.lang === 'ar';

  out.push({ json: {
    id,
    category_id: source.category_id,
    source_lang: source.lang,
    source_url: url,
    published_at: j.isoDate ? new Date(j.isoDate).toISOString() : new Date().toISOString(),
    // Source-language fields filled; counterpart language left empty
    // on purpose -- the "Translate" node fills the empty ones.
    title_ar: isAr ? title : '',
    title_en: isAr ? '' : title,
    short_description_ar: isAr ? short_description : '',
    short_description_en: isAr ? '' : short_description,
    description_ar: isAr ? description : '',
    description_en: isAr ? '' : description,
    rss_image: pickImage(j)
  }});
}

// Nothing usable from this feed: emit a single marker item so the
// "Has Articles?" IF node can route back to the loop with a reason.
if (out.length === 0) {
  const reason = items.length === 0 ? 'no_rss_items' : (skippedSeen === items.length ? 'all_already_seen' : 'no_usable_url');
  return [{ json: { _skip: true, _reason: reason, source_name: source.name, source_category_id: source.category_id } }];
}
return out;

// =====================================================================
// RESOLVE IMAGE + FULL TEXT -- enrich each article from its own page.
// - Image: RSS image first, else og:image / twitter:image meta tags.
// - Body:  extracts readable text from the page HTML (heuristic,
//          no external libraries) and uses it only if it is LONGER
//          than the feed's own summary (never regresses).
// =====================================================================
const orig = $('Build Articles').item.json;
const html = ($json.data || '').toString();
const MAX_DESCRIPTION_CHARS = $('Config').first().json.maxDescriptionChars;

// --- image: RSS enclosure first, else og:image / twitter:image ---
let image = orig.rss_image || '';
if (!image) {
  const m = html.match(/<meta[^>]+property=["']og:image["'][^>]+content=["']([^"']+)["']/i)
         || html.match(/<meta[^>]+content=["']([^"']+)["'][^>]+property=["']og:image["']/i)
         || html.match(/<meta[^>]+name=["']twitter:image["'][^>]+content=["']([^"']+)["']/i);
  if (m) image = m[1];
}

// --- full article text from the page HTML ---
function decode(s) {
  return s.replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/&#39;/g, "'").replace(/&quot;/g, '"').replace(/&lt;/g, '<').replace(/&gt;/g, '>');
}
function extractText(h) {
  if (!h) return '';
  let s = String(h);
  // Drop script/style/noscript blocks entirely.
  s = s.replace(/<script[\s\S]*?<\/script>/gi, ' ').replace(/<style[\s\S]*?<\/style>/gi, ' ').replace(/<noscript[\s\S]*?<\/noscript>/gi, ' ');
  // Prefer the <article> element when the page has one.
  let scope = s;
  const art = s.match(/<article[\s\S]*?<\/article>/i);
  if (art) scope = art[0];
  // Collect substantial <p> paragraphs (>= 40 chars).
  const blocks = scope.match(/<p[\s\S]*?<\/p>/gi) || [];
  const paras = [];
  for (const b of blocks) {
    const txt = decode(b.replace(/<[^>]*>/g, ' ')).replace(/\s+/g, ' ').trim();
    if (txt.length >= 40) paras.push(txt);
  }
  let text = paras.join('\n\n');
  // Fallback: strip ALL tags if paragraph extraction found too little.
  if (text.length < 200) {
    text = decode(scope.replace(/<[^>]*>/g, ' ')).replace(/\s+/g, ' ').trim();
  }
  return text;
}

let articleText = extractText(html);
if (articleText.length > MAX_DESCRIPTION_CHARS) {
  articleText = articleText.slice(0, MAX_DESCRIPTION_CHARS).trim() + '…';
}

const out = Object.assign({}, orig, { image });

// Replace the SOURCE-language description with the fuller body, only when
// the extraction beat the feed's own summary (never regress to shorter).
const isAr = orig.source_lang === 'ar';
const feedDesc = (isAr ? orig.description_ar : orig.description_en) || '';
if (articleText && articleText.length > feedDesc.length) {
  if (isAr) out.description_ar = articleText;
  else out.description_en = articleText;
}

return { json: out };

